import{_ as e,c as t,o as s,a1 as o}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"よくある質問: トラブルシューティングとセキュリティ | opencode-agent-skills","description":"プラグイン使用時のよくある問題とセキュリティ機構について学びます。スキルのロード失敗、スクリプトエラーなどの問題のトラブルシューティング方法、およびパス安全性、入力検証などのコアセキュリティ保護機構を解説します。","frontmatter":{"title":"よくある質問: トラブルシューティングとセキュリティ | opencode-agent-skills","sidebarTitle":"問題が発生したら","subtitle":"よくある質問: トラブルシューティングとセキュリティ","description":"プラグイン使用時のよくある問題とセキュリティ機構について学びます。スキルのロード失敗、スクリプトエラーなどの問題のトラブルシューティング方法、およびパス安全性、入力検証などのコアセキュリティ保護機構を解説します。","order":4},"headers":[],"relativePath":"ja/joshuadavidthomas/opencode-agent-skills/faq/index.md","filePath":"ja/joshuadavidthomas/opencode-agent-skills/faq/index.md"}'),l={name:"ja/joshuadavidthomas/opencode-agent-skills/faq/index.md"};function i(r,a,n,d,c,p){return s(),t("div",null,[...a[0]||(a[0]=[o('<h1 id="よくある質問" tabindex="-1">よくある質問 <a class="header-anchor" href="#よくある質問" aria-label="Permalink to &quot;よくある質問&quot;">​</a></h1><p>この章では、OpenCode Agent Skills プラグインの使用中に発生する問題の解決方法と、プラグインのセキュリティ機構について説明します。スキルのロード失敗、スクリプト実行エラー、プラグインがシステムをどのように保護しているかなど、あらゆる疑問にお答えします。</p><h2 id="本章の内容" tabindex="-1">本章の内容 <a class="header-anchor" href="#本章の内容" aria-label="Permalink to &quot;本章の内容&quot;">​</a></h2><div class="grid grid-cols-1 md:grid-cols-2 gap-4 mt-6"><a href="./troubleshooting/" class="block p-4 border rounded-lg hover:border-brand-500 transition-colors no-underline"><h3 class="text-lg font-semibold mb-2">🔧 よくある問題のトラブルシューティング</h3><p class="text-sm text-gray-600 dark:text-gray-400">スキルのロード失敗、スクリプト実行エラー、パス安全性の問題、モデルロード失敗など、9種類のよくある問題のトラブルシューティング方法と解決策を解説します。</p></a><a href="./security-considerations/" class="block p-4 border rounded-lg hover:border-brand-500 transition-colors no-underline"><h3 class="text-lg font-semibold mb-2">🔒 セキュリティについて</h3><p class="text-sm text-gray-600 dark:text-gray-400">プラグインのパス安全性チェック、YAML パース安全性、入力検証、スクリプト実行保護などのコアセキュリティ機構とベストプラクティスを学びます。</p></a></div><h2 id="学習パス" tabindex="-1">学習パス <a class="header-anchor" href="#学習パス" aria-label="Permalink to &quot;学習パス&quot;">​</a></h2><p>以下の順序で学習することをお勧めします：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>よくある問題のトラブルシューティング → セキュリティについて</span></span></code></pre></div><ol><li><strong>まずトラブルシューティングを学ぶ</strong>：問題が発生したら、まず「よくある問題のトラブルシューティング」で素早く原因を特定し解決する</li><li><strong>次にセキュリティを学ぶ</strong>：プラグインのセキュリティ機構を理解し、安全な使用習慣を身につける</li></ol><div class="tip custom-block"><p class="custom-block-title">問題が発生したら</p><p>プラグイン使用中に具体的な問題が発生した場合は、「よくある問題のトラブルシューティング」で該当する症状を直接検索してください。プラグインのセキュリティ設計を体系的に理解したい場合は、「セキュリティについて」をお読みください。</p></div><h2 id="前提条件" tabindex="-1">前提条件 <a class="header-anchor" href="#前提条件" aria-label="Permalink to &quot;前提条件&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">以下の章を先に完了することをお勧めします</p><ul><li><a href="./../start/">クイックスタート</a>：プラグインの基本概念とインストール方法を理解する</li><li><a href="./../platforms/">プラットフォーム機能</a>：スキルの発見、ロード、実行などのコア機能に慣れる</li></ul><p>この章の内容は、プラグインの基本的な理解があることを前提としています。初めて使用する場合は、上記の章を先に完了することをお勧めします。</p></div><h2 id="次のステップ" tabindex="-1">次のステップ <a class="header-anchor" href="#次のステップ" aria-label="Permalink to &quot;次のステップ&quot;">​</a></h2><p>この章を完了した後、さらに以下を探索できます：</p><ul><li><strong><a href="./../appendix/">付録</a></strong>：スキル開発のベストプラクティスと API ツールリファレンスを参照</li><li><strong><a href="./../changelog/">更新履歴</a></strong>：プラグインのバージョン変遷と新機能を確認</li></ul>',14)])])}const g=e(l,[["render",i]]);export{u as __pageData,g as default};
